#!/usr/bin/env node
// patch-mask-fix.cjs — Icône maskable 0.84 -> 0.75 (ne coupe plus les bords).
const fs=require('fs'); const path=require('path'); const ROOT=process.cwd();
let ok=0,fail=0;
function w(rel,b64){ try{ fs.writeFileSync(path.join(ROOT,rel),Buffer.from(b64,'base64')); console.log('  \u2705 '+rel); ok++; }catch(e){ console.log('  \u274c '+rel+': '+e.message); fail++; } }
console.log('\n  PATCH — Maskable (bords non coupés)\n');
w('public/icon-192-maskable.png','');
w('public/icon-512-maskable.png','');
console.log('\n  Résultat: '+ok+' \u2705   '+fail+' \u274c');
if(fail===0) console.log('\n\ud83c\udf89 npx vite build + push. PWA: désinstalle/réinstalle.\n');
